// Responsive Mixins
// --------------------------------------------------


// Creates a fixed width for the grid based on the screen size
// ---------------------------------------------------------------------------------

@mixin make-grid-widths($widths: $grid-widths, $breakpoints: $screen-breakpoints) {
  @each $breakpoint, $width in $widths {
    @include media-breakpoint-up($breakpoint, $breakpoints) {
      width: $width;
    }
  }

  max-width: 100%;
}

// Adds padding to the element based on breakpoints
// ---------------------------------------------------------------------------------

@mixin make-breakpoint-padding($paddings) {
  @each $breakpoint in map-keys($paddings) {
    @include media-breakpoint-up($breakpoint) {
      $padding: map-get($paddings, $breakpoint);

      @include padding($padding);
    }
  }
}

@mixin reset {
  @include vendor-prefixes.user-select(none);
  cursor: pointer;
  outline: none;
  border: none;
  -webkit-tap-highlight-color: transparent;

  // The `outline: none` from above works on all browsers, however Firefox also
  // adds a special `focus-inner` which we have to disable explicitly. See:
  // https://developer.mozilla.org/en-US/docs/Web/HTML/Element/button#Firefox
  &::-moz-focus-inner {
    border: 0;
  }
}

&:before {
  position: absolute;
  top: 0;
  inset-inline-start: 0;
  width: 100%;
  height: 100%;
  content: '';
  background: no-repeat center center/$form-check-input-checked-bg-size;
  background-image: escape-svg($form-check-input-checked-bg-image);
  opacity: 0;
  @include transition(opacity $transition-time);

  .form-colorinput-input:checked ~ & {
    opacity: 1;
  }
}

@mixin hook-inverse-component-grid(){

    .uk-grid-divider > :not(.uk-first-column)::before {
        border-left-color: $inverse-grid-divider-border;
        @if(meta.mixin-exists(hook-inverse-grid-divider-horizontal)) {@include hook-inverse-grid-divider-horizontal();}
    }

    .uk-grid-divider.uk-grid-stack > .uk-grid-margin::before {
        border-top-color: $inverse-grid-divider-border;
        @if(meta.mixin-exists(hook-inverse-grid-divider-vertical)) {@include hook-inverse-grid-divider-vertical();}
    }

}

@mixin hook-inverse-component-badge(){

    .uk-badge {
        background-color: $inverse-badge-background;
        color: $inverse-badge-color !important;
        @if(meta.mixin-exists(hook-inverse-badge)) {@include hook-inverse-badge();}
    }

    .uk-badge:hover {
        @if(meta.mixin-exists(hook-inverse-badge-hover)) {@include hook-inverse-badge-hover();}
    }

}

label {
  em.highlight {
    position: relative;
    left: calc(var(--base-size-4) * -1);
    // stylelint-disable-next-line primer/spacing
    padding: 2px var(--base-size-4);
    font-style: normal;
    background: var(--bgColor-attention-muted, var(--color-attention-subtle));
    // stylelint-disable-next-line primer/borders
    border-radius: $border-radius;
  }
}

dt, // TODO: Deprecate
    .form-group-header {
      label {
        display: inline-block;
        // stylelint-disable-next-line primer/spacing
        margin: 5px 0 0;
        color: var(--fgColor-muted, var(--color-fg-muted));
      }

      img {
        position: relative;
        // stylelint-disable-next-line primer/spacing
        top: -2px;
      }
    }

// iOS Alert Message
// --------------------------------------------------

.alert-message,
.alert-input-group {
  @include padding($alert-ios-message-padding-top, $alert-ios-message-padding-end, $alert-ios-message-padding-bottom, $alert-ios-message-padding-start);

  color: $alert-ios-message-text-color;

  font-size: $alert-ios-message-font-size;

  text-align: $alert-ios-message-text-align;
}

[aria-checked=true] .alert-radio-inner {
  @include position($alert-ios-radio-icon-top, null, null, $alert-ios-radio-icon-start);

  position: absolute;

  width: $alert-ios-radio-icon-width;
  height: $alert-ios-radio-icon-height;

  transform: $alert-ios-radio-icon-transform;

  border-width: $alert-ios-radio-icon-border-width;
  border-top-width: 0;
  border-left-width: 0;
  border-style: $alert-ios-radio-icon-border-style;
  border-color: $alert-ios-radio-icon-border-color;
}

// Material Design Tab Button: Icon
// --------------------------------------------------------------

::slotted(ion-icon) {
  @include margin($tab-button-md-icon-margin-top, $tab-button-md-icon-margin-end, $tab-button-md-icon-margin-bottom, $tab-button-md-icon-margin-start);
  @include transform-origin(center, center);

  font-size: $tab-button-md-icon-size;
}

// Material Design Tab Button: Badge
// --------------------------------------------------------------

::slotted(ion-badge) {
  @include border-radius($tab-button-md-badge-border-radius);
  @include padding($tab-button-md-badge-padding-top, $tab-button-md-badge-padding-end, $tab-button-md-badge-padding-bottom, $tab-button-md-badge-padding-start);
  @include position(8px, null, null, calc(50% + 6px));

  min-width: $tab-button-md-badge-min-width;

  font-size: $tab-button-md-badge-font-size;

  font-weight: normal;
}

