&.slds-is-selected {
  background-color: $brand-header-contrast-cool;
  border-color: $brand-header-contrast-cool;

  &:hover,
  &:focus {
    background-color: $brand-header-contrast-cool-active;
    border-color: $brand-header-contrast-cool-active;
  }

  .slds-button__icon {
    animation: click-favorites-icon 600ms cubic-bezier(0.46, 0.32, 0, 0.98);
  }
}

&:before {
  animation: none;
  animation-duration: 1s;
  animation-iteration-count: 3;
  animation-delay: 150ms;
  animation-timing-function: cubic-bezier(0.07, 0.49, 0.50, 1);
  background-color: $color;
  bottom: 0;
  content: '';
  height: auto;
  left: 0;
  position: absolute;
  right: 0;
  top: 0;
  transition: background-color 0.25s cubic-bezier(0.39, 0.575, 0.565, 1);
}

// Mimics slds-form-element__label
.slds-faux-input_label {
  display: inline-block;
  padding-right: $spacing-x-small;
  padding-top: $spacing-xx-small;
  margin-bottom: $spacing-xxx-small;
  font-size: $form-label-font-size;
  color: var(--slds-g-color-neutral-base-30, #{$color-text-label});
  overflow-wrap: break-word;
  word-wrap: break-word;
  hyphens: auto;
}

&.slds-popover_brand-dark {
  border-top-color: var(--slds-g-color-brand-base-10, #{$color-border-inverse});

  &.slds-nubbin_top:before,
  &.slds-nubbin_top-left:before,
  &.slds-nubbin_top-left-corner:before,
  &.slds-nubbin_top-right:before,
  &.slds-nubbin_top-right-corner:before {
    @include brand-nubbin($position: "top", $location: "before", $color: $color-border-inverse);
  }
}

&.slds-popover_brand-dark {
  border-left-color: var(--slds-g-color-brand-base-10, #{$color-border-inverse});

  &.slds-nubbin_left:before,
  &.slds-nubbin_left-top:before,
  &.slds-nubbin_left-top-corner:before,
  &.slds-nubbin_left-bottom:before,
  &.slds-nubbin_left-bottom-corner:before {
    @include brand-nubbin($position: "left", $location: "before", $color: $color-border-inverse);
  }
}

&.slds-popover_brand-dark {
  border-bottom-color: var(--slds-g-color-brand-base-10, #{$color-border-inverse});

  &.slds-nubbin_bottom:before,
  &.slds-nubbin_bottom-left:before,
  &.slds-nubbin_bottom-left-corner:before,
  &.slds-nubbin_bottom-right:before,
  &.slds-nubbin_bottom-right-corner:before {
    @include brand-nubbin($position: "bottom", $location: "before", $color: $color-border-inverse);
  }
}

&.slds-popover_brand-dark {
  border-right-color: var(--slds-g-color-brand-base-10, #{$color-border-inverse});

  &.slds-nubbin_right:before,
  &.slds-nubbin_right-top:before,
  &.slds-nubbin_right-top-corner:before,
  &.slds-nubbin_right-bottom:before,
  &.slds-nubbin_right-bottom-corner:before {
    @include brand-nubbin($position: "right", $location: "before", $color: $color-border-inverse);
  }
}

#{iv.$variables-host} {
  @include cv.register-vars(
    (
      "control-radius": #{$control-radius},
      "control-radius-small": #{$control-radius-small},
      "control-border-width": #{$control-border-width},
      "control-height": #{$control-height},
      "control-line-height": #{$control-line-height},
      "control-padding-vertical": #{$control-padding-vertical},
      "control-padding-horizontal": #{$control-padding-horizontal},
      "control-size": #{$control-size},
      "control-focus-shadow-l": #{$control-focus-shadow-l},
    )
  );
}

@function private-get-color-palette-color-tokens($theme, $color-variant) {
  $system: m2-utils.get-system($theme);
  $system: m3-utils.replace-colors-with-variant($system, primary, $color-variant);

  @return (
    icon-button-icon-color: map.get($system, primary),
    icon-button-state-layer-color: map.get($system, primary),
    icon-button-ripple-color: m3-utils.color-with-opacity(
        map.get($system, primary), map.get($system, pressed-state-layer-opacity)),
  );
}
